(window.webpackJsonp=window.webpackJsonp||[]).push([[64],{691:function(n,t){n.exports='\x3c!-- \ntitle: 04-Go进阶\nsort: \n--\x3e \n\n## 接口\n\n> 将不同类型中相同的方法定义在一起\n\n```go\npackage main\n\nimport "fmt"\n\n// 定义接口 内部两个方法\ntype Phone interface {\n    call(param int) string\n    takephoto()\n}\n\n// 结构体实例\ntype Xiaomi struct {\n}\n\n// 为Xiaomi定义call方法\nfunc (mi Xiaomi) call(param int) string{\n    fmt.Println("I\'m Xioami: ", param)\n    return "I\'m death"\n}\n\nfunc (mi Xiaomi) takephoto() {\n    fmt.Println("I take a photo.")\n}\n\nfunc main(){\n    // 新建接口\n    var phone Phone\n    // 接口获得一个结构体\n    phone = new(Xiaomi)\n    // 调用结构体接口的方法\n    phone.takephoto()\n    // 调用带参数的方法\n    r := phone.call(404)\n    fmt.Println(r)\n}\n/*\nI take a photo.\nI\'m Xioami:  404\nI\'m death\n*/\n```\n\n'}}]);